    VALUES
    ('3da3a459-d3c2-48af-b8d0-02bc95146468', 'SV29', false, NOW(), NOW(), 'CHE101708094', jsonb_build_object('de','Basisdaten für Zertifizierung Bio Suisse','fr','Données de base pour la certification Bio Suisse','it','Dati di base per la certificazione Bio Suisse'), jsonb_build_object('de','Übermittlung von Personen- und Betriebsdaten zur Prüfung der Grundvoraussetzungen für eine Bio Suisse-Zertifizierung.','fr','Transmission des données personnelles et d''exploitation pour vérifier les conditions de base de la certification Bio Suisse.','it','Trasmissione dei dati personali e aziendali per la verifica dei requisiti base per la certificazione Bio Suisse.'), jsonb_build_object('de','Vereinfachung der Erstprüfung im Zertifizierungsprozess und Reduktion manueller Dateneingabe.','fr','Simplification du contrôle initial dans le processus de certification et réduction de la saisie manuelle des données.','it','Semplificazione del controllo iniziale nel processo di certificazione e riduzione dell’inserimento manuale dei dati.'), 'ACTIVE', '2025-03-11 09:27:55'::timestamp, 'Basel', 'CH', 'INTERNATIONAL CERTIFICATION BIO SUISSE AG', 'Bio Suisse', 'Peter Merian-Str. 34', '4052', '+41 61 204 66 66', 'bio@bio-suisse.ch', 'Alle Bio Suisse Produzenten', '^https:\/\/([A-Za-z0-9-]+\.)*bio-suisse\.[A-Za-z0-9.-]+(\/.*)?$', '5335d715-e95c-4777-a424-ab73f2ff5618', 'COLLECTIVE_SIGNATURE', 'COLLECTIVE_SIGNATURE'),
    ('81ae8571-9497-413a-99c5-237e72621ca7', 'TE33',false, NOW(), NOW(), 'CHE101708094', jsonb_build_object('de','Tierdaten zur Kontrolle der Richtlinienkonformität','fr','Données animales pour le contrôle de conformité aux directives','it','Dati sugli animali per il controllo della conformità alle direttive'), jsonb_build_object('de','Übermittlung von Tierdaten zur Prüfung der Haltungsform, Fütterung und Tieranzahl gemäss den Bio Suisse-Richtlinien.','fr','Transmission de données sur les animaux pour vérifier le mode d''élevage, l''alimentation et le nombre d’animaux selon les directives Bio Suisse.','it','Trasmissione dei dati relativi agli animali per verificare il tipo di allevamento, l’alimentazione e il numero di capi secondo le direttive Bio Suisse.'), jsonb_build_object('de','Sicherstellung der Einhaltung der Tierwohl- und Haltungsanforderungen im Bio Suisse-System.','fr','Assurer le respect des exigences en matière de bien-être animal et d’élevage dans le système Bio Suisse.','it','Garantire il rispetto dei requisiti relativi al benessere animale e all’allevamento nel sistema Bio Suisse.'), 'ACTIVE','2025-02-08 14:22:23'::timestamp, 'Basel', 'CH', 'INTERNATIONAL CERTIFICATION BIO SUISSE AG', 'Bio Suisse', 'Peter Merian-Str. 34', '4052', '+41 61 204 66 66', 'bio@bio-suisse.ch', 'Alle Bio Suisse Produzenten','^https:\/\/([A-Za-z0-9-]+\.)*bio-suisse\.[A-Za-z0-9.-]+(\/.*)?$', '5335d715-e95c-4777-a424-ab73f2ff5618', 'COLLECTIVE_SIGNATURE', 'COLLECTIVE_SIGNATURE'),
    ('98a35e61-0162-4986-9e9e-ee5c65f86316', 'KP76',false, NOW(), NOW(), 'CHE110013660', jsonb_build_object('de','Rebbau und Biodiversität im IP-Suisse Programm','fr','Viticulture et biodiversité dans le programme IP-Suisse','it','Viticoltura e biodiversità nel programma IP-Suisse'), jsonb_build_object('de','Erhebung von Rebflächen in Hanglagen und biodiversitätsfördernden Strukturen zur Förderung nachhaltiger Anbaumethoden im Rebbau.','fr','Collecte des surfaces viticoles en pente et des structures favorisant la biodiversité pour promouvoir des méthodes durables en viticulture.','it','Raccolta di superfici vitate in pendenza e strutture che promuovono la biodiversità per sostenere metodi sostenibili nella viticoltura.'), jsonb_build_object('de','Verbesserung der ökologischen Bewertung von Rebflächen und gezielte Förderung biodiversitätsfreundlicher Massnahmen.','fr','Amélioration de l’évaluation écologique des surfaces viticoles et promotion ciblée de mesures favorables à la biodiversité.','it','Miglioramento della valutazione ecologica delle superfici vitate e promozione mirata di misure favorevoli alla biodiversità.'), 'ACTIVE','2025-04-01 07:12:05'::timestamp, 'Zollikofen', 'CH', 'Schweizerische Vereinigung integriert produzierender Bauern und Bäuerinnen (IP-SUISSE)', 'IP-SUISSE', 'Molkereistrasse 21', '3052', '+41 31 910 60 00', 'info@ipsuisse.ch', 'Alle IP-SUISSE Produzenten','^.*$', '5335d715-e95c-4777-a424-ab73f2ff5618', 'COLLECTIVE_SIGNATURE', 'COLLECTIVE_SIGNATURE'),
    ('341f558a-781c-4eb5-bab7-c2f39216b9f2', 'QW94',false, NOW(), NOW(), 'CHE110013660', jsonb_build_object('de','Flächennachweis für Hanglagen und Hauptkulturen','fr','Déclaration des surfaces en pente et cultures principales','it','Dichiarazione delle superfici in pendenza e colture principali'), jsonb_build_object('de','Nutzung von Flächendaten zur Kontrolle der IP-Suisse-Vorgaben bezüglich Hanglagen und Anbauvielfalt.','fr','Utilisation des données de surface pour contrôler les exigences IP-Suisse concernant les pentes et la diversité culturale.','it','Utilizzo dei dati sulle superfici per verificare i requisiti IP-Suisse su pendii e varietà colturale.'), jsonb_build_object('de','Reduktion von administrativem Aufwand und Sicherstellung der Richtlinieneinhaltung.','fr','Réduction de la charge administrative et garantie du respect des directives.','it','Riduzione del carico amministrativo e garanzia del rispetto delle direttive.'), 'ACTIVE','2025-01-25 13:54:13'::timestamp, 'Zollikofen', 'CH', 'Schweizerische Vereinigung integriert produzierender Bauern und Bäuerinnen (IP-SUISSE)', 'IP-SUISSE', 'Molkereistrasse 21', '3052', '+41 31 910 60 00', 'info@ipsuisse.ch', 'Alle IP-SUISSE Produzenten','^.*$', '5335d715-e95c-4777-a424-ab73f2ff5618', 'COLLECTIVE_SIGNATURE', 'COLLECTIVE_SIGNATURE'),
    ('218bca06-e792-4855-bcd9-e3559cea3d18', 'KR11', false, NOW(), NOW(), 'CHE403244345', jsonb_build_object( 'de','Antrag auf Animal Tracing Daten für das Bundesamt für Lebensmittelsicherheit und Veterinärwesen', 'fr','Demande de données de traçabilité animale pour l’Office fédéral de la sécurité alimentaire et des affaires vétérinaires', 'it','Richiesta di dati di tracciabilità animale per l’Ufficio federale della sicurezza alimentare e di veterinaria'), jsonb_build_object( 'de','Das Bundesamt für Lebensmittelsicherheit und Veterinärwesen beantragt die Bereitstellung von Animal Tracing Daten', 'fr','L’Office fédéral de la sécurité alimentaire et des affaires vétérinaires demande la mise à disposition de données de traçabilité animale', 'it','L’Ufficio federale della sicurezza alimentare e di veterinaria richiede la messa a disposizione di dati di tracciabilità animale' ), jsonb_build_object( 'de','Nutzung zur Kontrollvorbereitung, zur Weiterentwicklung von Richtlinien sowie für aggregiertes Monitoring und Reporting, ohne Weitergabe und ohne Marketing.', 'fr','Utilisation pour la préparation des contrôles, le développement des directives ainsi que pour le suivi et le reporting agrégés, sans transmission et sans marketing.', 'it','Utilizzo per la preparazione dei controlli, per lo sviluppo delle direttive nonché per il monitoraggio e il reporting aggregati, senza condivisione e senza marketing.' ), 'ACTIVE', '2026-02-18 09:27:55'::timestamp, 'Bern', 'CH', 'Bundesamt für Lebensmittelsicherheit und Veterinärwesen BLV', 'Bundesamt für Lebensmittelsicherheit und Veterinärwesen BLV', 'Schwarzenburgstrasse 155', '3003', '+41 00 000 000', 'dummy@dummy.com', 'Alle Datenproduzenten', '^.*$', '4ccbfa06-a547-4a76-9dfc-61c22a4ea8ce', 'COLLECTIVE_SIGNATURE', 'COLLECTIVE_SIGNATURE'),
    ('dc7dbc72-084c-451f-aaf9-7db7561d157d', 'FA87', false, NOW(), NOW(), 'CHE403244345', jsonb_build_object( 'de','Antrag auf Zuchtorganisationsdaten für das Bundesamt für Lebensmittelsicherheit und Veterinärwesen', 'fr','Demande de données des organisations d’élevage pour l’Office fédéral de la sécurité alimentaire et des affaires vétérinaires', 'it','Richiesta di dati delle organizzazioni di allevamento per l’Ufficio federale della sicurezza alimentare e di veterinaria' ), jsonb_build_object( 'de','Das Bundesamt für Lebensmittelsicherheit und Veterinärwesen beantragt die Bereitstellung von Zuchtorganisationsdaten', 'fr','L’Office fédéral de la sécurité alimentaire et des affaires vétérinaires demande la mise à disposition de données des organisations d’élevage', 'it','L’Ufficio federale della sicurezza alimentare e di veterinaria richiede la messa a disposizione di dati delle organizzazioni di allevamento' ), jsonb_build_object( 'de','Nutzung zur Kontrollvorbereitung, zur Weiterentwicklung von Richtlinien sowie für aggregiertes Monitoring und Reporting, ohne Weitergabe und ohne Marketing.', 'fr','Utilisation pour la préparation des contrôles, le développement des directives ainsi que pour le suivi et le reporting agrégés, sans transmission et sans marketing.', 'it','Utilizzo per la preparazione dei controlli, per lo sviluppo delle direttive nonché per il monitoraggio e il reporting aggregati, senza condivisione e senza marketing.' ), 'ACTIVE', '2026-02-25 10:38:55'::timestamp, 'Bern', 'CH', 'Bundesamt für Lebensmittelsicherheit und Veterinärwesen BLV', 'Bundesamt für Lebensmittelsicherheit und Veterinärwesen BLV', 'Schwarzenburgstrasse 155', '3003', '+41 00 000 000', 'dummy@dummy.com', 'Alle Datenproduzenten', '^.*$', 'e93f1023-850d-4188-bf40-50e5eedaaa57', 'COLLECTIVE_SIGNATURE', 'COLLECTIVE_SIGNATURE');

